    public int[] getPast7DaysActivity() {
        int[] result = new int[7];
        java.util.Calendar cal = java.util.Calendar.getInstance();
        SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd", Locale.getDefault());

        for (int i = 6; i >= 0; i--) {
            String dateStr = sdf.format(cal.getTime());
            if (i == 6) { // Today
                result[i] = getHorofCount() + getSouarCount(); // simple combined metric for the chart
            } else {
                int h = sharedPreferences.getInt("horof_history_" + dateStr, 0);
                int s = sharedPreferences.getInt("souar_history_" + dateStr, 0);
                result[i] = h + s;
            }
            cal.add(java.util.Calendar.DAY_OF_YEAR, -1);
        }
        return result;
    }

    public boolean[] getPast7DaysActiveStatus() {
        boolean[] result = new boolean[7];
        java.util.Calendar cal = java.util.Calendar.getInstance();
        SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd", Locale.getDefault());

        for (int i = 6; i >= 0; i--) {
            String dateStr = sdf.format(cal.getTime());
            if (i == 6) { // Today
                result[i] = (getHorofCount() > 0 || getSouarCount() > 0);
            } else {
                int h = sharedPreferences.getInt("horof_history_" + dateStr, 0);
                int s = sharedPreferences.getInt("souar_history_" + dateStr, 0);
                result[i] = (h > 0 || s > 0);
            }
            cal.add(java.util.Calendar.DAY_OF_YEAR, -1);
        }
        return result;
    }

    public int getCurrentStreak() {
        int streak = 0;
        java.util.Calendar cal = java.util.Calendar.getInstance();
        SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd", Locale.getDefault());

        boolean todayActive = (getHorofCount() > 0 || getSouarCount() > 0);
        if (todayActive) {
            streak++;
        }

        cal.add(java.util.Calendar.DAY_OF_YEAR, -1);

        String yesterdayStr = sdf.format(cal.getTime());
        int yh = sharedPreferences.getInt("horof_history_" + yesterdayStr, 0);
        int ys = sharedPreferences.getInt("souar_history_" + yesterdayStr, 0);
        boolean yesterdayActive = (yh > 0 || ys > 0);

        if (!todayActive && !yesterdayActive) {
            return 0; // streak broken
        }

        // Now count backwards from yesterday
        while (true) {
            String dateStr = sdf.format(cal.getTime());
            int h = sharedPreferences.getInt("horof_history_" + dateStr, 0);
            int s = sharedPreferences.getInt("souar_history_" + dateStr, 0);
            if (h > 0 || s > 0) {
                streak++;
                cal.add(java.util.Calendar.DAY_OF_YEAR, -1);
            } else {
                break;
            }
        }
        return streak;
    }
}

